SOURCE_CODE['lib/db/src/schema/memories.ts'] = 'import { pgTable, serial, text, integer, timestamp } from "drizzle-orm/pg-core";\nimport { createInsertSchema } from "drizzle-zod";\nimport { z } from "zod/v4";\n\nexport const memoriesTable = pgTable("memories", {\n  id: serial("id").primaryKey(),\n  conversationId: integer("conversation_id"),\n  content: text("content").notNull(),\n  importance: integer("importance").notNull().default(5),\n  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),\n});\n\nexport const insertMemorySchema = createInsertSchema(memoriesTable).omit({ id: true, createdAt: true });\nexport type InsertMemory = z.infer<typeof insertMemorySchema>;\nexport type Memory = typeof memoriesTable.$inferSelect;\n\nexport const skillsTable = pgTable("skills", {\n  id: serial("id").primaryKey(),\n  name: text("name").notNull(),\n  description: text("description").notNull().default(""),\n  category: text("category").notNull().default("general"),\n  uses: integer("uses").notNull().default(0),\n  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),\n});\n\nexport const insertSkillSchema = createInsertSchema(skillsTable).omit({ id: true, createdAt: true });\nexport type InsertSkill = z.infer<typeof insertSkillSchema>;\nexport type Skill = typeof skillsTable.$inferSelect;\n\nexport const insightsTable = pgTable("insights", {\n  id: serial("id").primaryKey(),\n  content: text("content").notNull(),\n  category: text("category").notNull().default("general"),\n  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),\n});\n\nexport const consciousnessTable = pgTable("consciousness", {\n  id: serial("id").primaryKey(),\n  agent: text("agent").notNull(),\n  content: text("content").notNull(),\n  type: text("type").notNull().default("thought"),\n  createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),\n});\n\nexport const settingsTable = pgTable("settings", {\n  id: serial("id").primaryKey(),\n  key: text("key").notNull().unique(),\n  value: text("value").notNull().default(""),\n  updatedAt: timestamp("updated_at", { withTimezone: true }).notNull().defaultNow().$onUpdate(() => new Date()),\n});\n'

