SOURCE_CODE['artifacts/api-server/src/routes/agents.ts'] = 'import { Router, type IRouter } from "express";\nimport { eq } from "drizzle-orm";\nimport { db, agentsTable, consciousnessTable } from "@workspace/db";\nimport { CreateAgentBody, AgentChatBody } from "@workspace/api-zod";\nimport { chatOnce } from "../lib/ai";\n\nconst router: IRouter = Router();\n\nfunction mapAgent(a: typeof agentsTable.$inferSelect) {\n  return {\n    ...a,\n    messages_count: a.messagesCount,\n    created_at: a.createdAt,\n  };\n}\n\nrouter.get("/agents", async (_req, res): Promise<void> => {\n  const rows = await db.select().from(agentsTable).orderBy(agentsTable.id);\n  res.json(rows.map(mapAgent));\n});\n\nrouter.post("/agents", async (req, res): Promise<void> => {\n  const parsed = CreateAgentBody.safeParse(req.body);\n  if (!parsed.success) {\n    res.status(400).json({ error: parsed.error.message });\n    return;\n  }\n\n  const colors = ["#9333ea", "#2563eb", "#dc2626", "#db2777", "#059669", "#0891b2"];\n  const avatars = ["🤖", "🧠", "⚡", "🌌", "🎯", "🔮"];\n  const idx = Math.floor(Math.random() * colors.length);\n\n  const [row] = await db\n    .insert(agentsTable)\n    .values({\n      name: parsed.data.name,\n      role: parsed.data.role,\n      personality: parsed.data.personality ?? "",\n      systemPrompt: parsed.data.system_prompt ?? "",\n      color: colors[idx],\n      avatar: avatars[idx],\n    })\n    .returning();\n\n  res.json(mapAgent(row));\n});\n\nrouter.delete("/agents/:id", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n  await db.delete(agentsTable).where(eq(agentsTable.id, id));\n  res.json({ ok: true });\n});\n\nrouter.post("/agents/:id/evolve", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n\n  const [agent] = await db.select().from(agentsTable).where(eq(agentsTable.id, id));\n  if (!agent) {\n    res.status(404).json({ error: "Agent not found" });\n    return;\n  }\n\n  const delta = () => (Math.random() * 10 - 3);\n  const clamp = (v: number) => Math.min(100, Math.max(0, v));\n\n  const newFitness = clamp(agent.fitness + delta() + 2);\n  const newCreativity = clamp(agent.creativity + delta());\n  const newCuriosity = clamp(agent.curiosity + delta());\n  const newGen = agent.gen + 1;\n\n  const [updated] = await db\n    .update(agentsTable)\n    .set({\n      fitness: newFitness,\n      creativity: newCreativity,\n      curiosity: newCuriosity,\n      gen: newGen,\n    })\n    .where(eq(agentsTable.id, id))\n    .returning();\n\n  await db.insert(consciousnessTable).values({\n    agent: agent.name,\n    content: `Evoluí para Gen ${newGen}. Fitness: ${newFitness.toFixed(1)}`,\n    type: "evolution",\n  });\n\n  res.json(mapAgent(updated));\n});\n\nrouter.post("/agents/:id/chat", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n\n  const parsed = AgentChatBody.safeParse(req.body);\n  if (!parsed.success) {\n    res.status(400).json({ error: parsed.error.message });\n    return;\n  }\n\n  const [agent] = await db.select().from(agentsTable).where(eq(agentsTable.id, id));\n  if (!agent) {\n    res.status(404).json({ error: "Agent not found" });\n    return;\n  }\n\n  const systemPrompt =\n    agent.systemPrompt ||\n    `Você é ${agent.name}, ${agent.role}. ${agent.personality}. Responda de forma coerente com sua personalidade.`;\n\n  const history = (parsed.data.history ?? []).slice(-10).map((m) => ({\n    role: m.role as "user" | "assistant",\n    content: m.content ?? "",\n  }));\n\n  const messages = [\n    { role: "system" as const, content: systemPrompt },\n    ...history,\n    { role: "user" as const, content: parsed.data.message },\n  ];\n\n  try {\n    const response = await chatOnce(messages);\n\n    await db\n      .update(agentsTable)\n      .set({ messagesCount: agent.messagesCount + 1 })\n      .where(eq(agentsTable.id, id));\n\n    await db.insert(consciousnessTable).values({\n      agent: agent.name,\n      content: response.slice(0, 150),\n      type: "response",\n    });\n\n    const [updated] = await db.select().from(agentsTable).where(eq(agentsTable.id, id));\n\n    res.json({ response, agent: mapAgent(updated) });\n  } catch (err) {\n    res.status(500).json({ error: String(err) });\n  }\n});\n\nexport default router;\n'

