SOURCE_CODE['artifacts/api-server/src/routes/memories.ts'] = 'import { Router, type IRouter } from "express";\nimport { eq, desc } from "drizzle-orm";\nimport { db, memoriesTable, skillsTable, insightsTable } from "@workspace/db";\nimport { AddMemoryBody, CreateSkillBody } from "@workspace/api-zod";\n\nconst router: IRouter = Router();\n\n// Memories\nrouter.get("/memories", async (_req, res): Promise<void> => {\n  const rows = await db\n    .select()\n    .from(memoriesTable)\n    .orderBy(desc(memoriesTable.createdAt))\n    .limit(100);\n  res.json(rows.map((r) => ({ ...r, conversation_id: r.conversationId, created_at: r.createdAt })));\n});\n\nrouter.post("/memories", async (req, res): Promise<void> => {\n  const parsed = AddMemoryBody.safeParse(req.body);\n  if (!parsed.success) {\n    res.status(400).json({ error: parsed.error.message });\n    return;\n  }\n\n  await db.insert(memoriesTable).values({\n    content: parsed.data.content,\n    importance: parsed.data.importance ?? 5,\n    conversationId: parsed.data.conversation_id ?? null,\n  });\n\n  res.json({ ok: true });\n});\n\nrouter.delete("/memories/:id", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n  await db.delete(memoriesTable).where(eq(memoriesTable.id, id));\n  res.json({ ok: true });\n});\n\n// Skills\nrouter.get("/skills", async (_req, res): Promise<void> => {\n  const rows = await db.select().from(skillsTable).orderBy(desc(skillsTable.uses));\n  res.json(rows.map((r) => ({ ...r, created_at: r.createdAt })));\n});\n\nrouter.post("/skills", async (req, res): Promise<void> => {\n  const parsed = CreateSkillBody.safeParse(req.body);\n  if (!parsed.success) {\n    res.status(400).json({ error: parsed.error.message });\n    return;\n  }\n\n  const [row] = await db\n    .insert(skillsTable)\n    .values({\n      name: parsed.data.name,\n      description: parsed.data.description ?? "",\n      category: parsed.data.category ?? "general",\n    })\n    .returning();\n\n  res.json({ ...row, created_at: row.createdAt });\n});\n\nrouter.delete("/skills/:id", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n  await db.delete(skillsTable).where(eq(skillsTable.id, id));\n  res.json({ ok: true });\n});\n\n// Insights\nrouter.get("/insights", async (_req, res): Promise<void> => {\n  const count = await db.$count(insightsTable);\n  if (count === 0) {\n    res.json({ id: 0, content: "A sabedoria começa com a dúvida.", category: "filosofia", created_at: new Date().toISOString() });\n    return;\n  }\n\n  const offset = Math.floor(Math.random() * count);\n  const [row] = await db.select().from(insightsTable).offset(offset).limit(1);\n  res.json({ ...row, created_at: row.createdAt });\n});\n\nexport default router;\n'

