SOURCE_CODE['artifacts/api-server/src/routes/projects.ts'] = 'import { Router, type IRouter } from "express";\nimport { eq, sql } from "drizzle-orm";\nimport { db, projectsTable, conversationsTable } from "@workspace/db";\nimport { CreateProjectBody } from "@workspace/api-zod";\n\nconst router: IRouter = Router();\n\nrouter.get("/projects", async (_req, res): Promise<void> => {\n  const rows = await db.select().from(projectsTable).orderBy(projectsTable.createdAt);\n\n  const counts = await db\n    .select({\n      projectId: conversationsTable.projectId,\n      n: sql<number>`count(*)::int`,\n    })\n    .from(conversationsTable)\n    .groupBy(conversationsTable.projectId);\n\n  const countMap = new Map(counts.map((c) => [c.projectId, c.n]));\n\n  res.json(\n    rows.map((r) => ({\n      ...r,\n      chat_count: countMap.get(r.id) ?? 0,\n      created_at: r.createdAt,\n      updated_at: r.updatedAt,\n    })),\n  );\n});\n\nrouter.post("/projects", async (req, res): Promise<void> => {\n  const parsed = CreateProjectBody.safeParse(req.body);\n  if (!parsed.success) {\n    res.status(400).json({ error: parsed.error.message });\n    return;\n  }\n\n  const [row] = await db\n    .insert(projectsTable)\n    .values({\n      name: parsed.data.name,\n      description: parsed.data.description ?? "",\n      color: parsed.data.color ?? "#7c3aed",\n      icon: parsed.data.icon ?? "📁",\n    })\n    .returning();\n\n  res.json({ ...row, chat_count: 0, created_at: row.createdAt, updated_at: row.updatedAt });\n});\n\nrouter.delete("/projects/:id", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n\n  await db.delete(projectsTable).where(eq(projectsTable.id, id));\n  res.json({ ok: true });\n});\n\nexport default router;\n'

