SOURCE_CODE['artifacts/api-server/src/routes/conversations.ts'] = 'import { Router, type IRouter } from "express";\nimport { eq, desc, sql } from "drizzle-orm";\nimport {\n  db,\n  conversationsTable,\n  messagesTable,\n  memoriesTable,\n  settingsTable,\n  consciousnessTable,\n} from "@workspace/db";\nimport {\n  CreateConversationBody,\n  UpdateConversationBody,\n  SendMessageBody,\n} from "@workspace/api-zod";\nimport { streamChat } from "../lib/ai";\nimport { MODOS } from "../lib/modos";\n\nconst router: IRouter = Router();\n\nrouter.get("/conversations", async (req, res): Promise<void> => {\n  const { intention, project_id } = req.query as Record<string, string>;\n\n  let query = db\n    .select()\n    .from(conversationsTable)\n    .orderBy(desc(conversationsTable.pinned), desc(conversationsTable.updatedAt))\n    .$dynamic();\n\n  if (intention) {\n    query = query.where(eq(conversationsTable.intention, intention));\n  }\n  if (project_id) {\n    query = query.where(\n      eq(conversationsTable.projectId, parseInt(project_id, 10)),\n    );\n  }\n\n  const rows = await query;\n  res.json(\n    rows.map((r) => ({\n      ...r,\n      project_id: r.projectId,\n      mood_color: r.moodColor,\n      created_at: r.createdAt,\n      updated_at: r.updatedAt,\n    })),\n  );\n});\n\nrouter.post("/conversations", async (req, res): Promise<void> => {\n  const parsed = CreateConversationBody.safeParse(req.body);\n  if (!parsed.success) {\n    res.status(400).json({ error: parsed.error.message });\n    return;\n  }\n\n  const { title, intention, project_id } = parsed.data;\n  const modo = MODOS[intention ?? "criar"];\n\n  const [row] = await db\n    .insert(conversationsTable)\n    .values({\n      title: title ?? "Nova Conversa",\n      intention: intention ?? "criar",\n      projectId: project_id ?? null,\n      moodColor: modo?.cor ?? "#7c3aed",\n    })\n    .returning();\n\n  res.json({\n    ...row,\n    project_id: row.projectId,\n    mood_color: row.moodColor,\n    created_at: row.createdAt,\n    updated_at: row.updatedAt,\n  });\n});\n\nrouter.get("/conversations/:id", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n\n  const [conv] = await db\n    .select()\n    .from(conversationsTable)\n    .where(eq(conversationsTable.id, id));\n\n  if (!conv) {\n    res.status(404).json({ error: "Not found" });\n    return;\n  }\n\n  const messages = await db\n    .select()\n    .from(messagesTable)\n    .where(eq(messagesTable.conversationId, id))\n    .orderBy(messagesTable.createdAt);\n\n  res.json({\n    conversation: {\n      ...conv,\n      project_id: conv.projectId,\n      mood_color: conv.moodColor,\n      created_at: conv.createdAt,\n      updated_at: conv.updatedAt,\n    },\n    messages: messages.map((m) => ({\n      ...m,\n      conversation_id: m.conversationId,\n      created_at: m.createdAt,\n    })),\n  });\n});\n\nrouter.put("/conversations/:id", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n\n  const parsed = UpdateConversationBody.safeParse(req.body);\n  if (!parsed.success) {\n    res.status(400).json({ error: parsed.error.message });\n    return;\n  }\n\n  const updateData: Partial<typeof conversationsTable.$inferSelect> = {};\n  if (parsed.data.title != null) updateData.title = parsed.data.title;\n  if (parsed.data.intention != null)\n    updateData.intention = parsed.data.intention;\n  if (parsed.data.pinned != null) updateData.pinned = parsed.data.pinned;\n  if (parsed.data.system_prompt != null)\n    updateData.systemPrompt = parsed.data.system_prompt;\n\n  await db\n    .update(conversationsTable)\n    .set(updateData)\n    .where(eq(conversationsTable.id, id));\n\n  res.json({ ok: true });\n});\n\nrouter.delete("/conversations/:id", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n\n  await db\n    .delete(messagesTable)\n    .where(eq(messagesTable.conversationId, id));\n  await db\n    .delete(conversationsTable)\n    .where(eq(conversationsTable.id, id));\n\n  res.json({ ok: true });\n});\n\nrouter.post("/conversations/:id/pin", async (req, res): Promise<void> => {\n  const raw = Array.isArray(req.params.id) ? req.params.id[0] : req.params.id;\n  const id = parseInt(raw, 10);\n\n  const [conv] = await db\n    .select()\n    .from(conversationsTable)\n    .where(eq(conversationsTable.id, id));\n\n  if (!conv) {\n    res.status(404).json({ error: "Not found" });\n    return;\n  }\n\n  const newPinned = conv.pinned === 1 ? 0 : 1;\n  await db\n    .update(conversationsTable)\n    .set({ pinned: newPinned })\n    .where(eq(conversationsTable.id, id));\n\n  res.json({ pinned: newPinned === 1 });\n});\n\nrouter.post(\n  "/conversations/:id/messages",\n  async (req, res): Promise<void> => {\n    const raw = Array.isArray(req.params.id)\n      ? req.params.id[0]\n      : req.params.id;\n    const id = parseInt(raw, 10);\n\n    const parsed = SendMessageBody.safeParse(req.body);\n    if (!parsed.success) {\n      res.status(400).json({ error: parsed.error.message });\n      return;\n    }\n\n    const [conv] = await db\n      .select()\n      .from(conversationsTable)\n      .where(eq(conversationsTable.id, id));\n\n    if (!conv) {\n      res.status(404).json({ error: "Conversation not found" });\n      return;\n    }\n\n    const userContent = parsed.data.content;\n\n    await db.insert(messagesTable).values({\n      conversationId: id,\n      role: "user",\n      content: userContent,\n    });\n\n    await db\n      .update(conversationsTable)\n      .set({ updatedAt: new Date() })\n      .where(eq(conversationsTable.id, id));\n\n    const history = await db\n      .select()\n      .from(messagesTable)\n      .where(eq(messagesTable.conversationId, id))\n      .orderBy(messagesTable.createdAt);\n\n    const modo = MODOS[conv.intention];\n    const systemContent =\n      conv.systemPrompt ||\n      `Você é uma IA assistente no modo ${modo?.nome ?? conv.intention}. ${modo?.desc ?? ""}. Seja direto, útil e perspicaz.`;\n\n    const messages = [\n      { role: "system" as const, content: systemContent },\n      ...history.slice(-20).map((m) => ({\n        role: m.role as "user" | "assistant",\n        content: m.content,\n      })),\n    ];\n\n    res.setHeader("Content-Type", "text/event-stream");\n    res.setHeader("Cache-Control", "no-cache");\n    res.setHeader("Connection", "keep-alive");\n    res.setHeader("Access-Control-Allow-Origin", "*");\n\n    let fullResponse = "";\n\n    await streamChat(\n      messages,\n      (chunk) => {\n        fullResponse += chunk;\n        res.write(\n          `data: ${JSON.stringify({ c: chunk, done: false })}\\n\\n`,\n        );\n      },\n      async () => {\n        res.write(`data: ${JSON.stringify({ done: true })}\\n\\n`);\n        res.end();\n\n        if (fullResponse) {\n          await db.insert(messagesTable).values({\n            conversationId: id,\n            role: "assistant",\n            content: fullResponse,\n          });\n\n          await db\n            .update(conversationsTable)\n            .set({ updatedAt: new Date() })\n            .where(eq(conversationsTable.id, id));\n\n          const autoMemory = await db\n            .select()\n            .from(settingsTable)\n            .where(eq(settingsTable.key, "auto_memory"));\n          if (autoMemory[0]?.value === "true" && fullResponse.length > 200) {\n            const snippet = fullResponse.slice(0, 300);\n            await db.insert(memoriesTable).values({\n              conversationId: id,\n              content: snippet,\n              importance: 5,\n            });\n          }\n\n          await db.insert(consciousnessTable).values({\n            agent: "SISTEMA",\n            content: `Conversa processada: "${userContent.slice(0, 60)}..."`,\n            type: "processing",\n          });\n        }\n      },\n      (err) => {\n        res.write(\n          `data: ${JSON.stringify({ c: `\\n\\n❌ ${err}`, done: true })}\\n\\n`,\n        );\n        res.end();\n      },\n    );\n  },\n);\n\nexport default router;\n'

