SOURCE_CODE['artifacts/kokusen/src/pages/agents.tsx'] = 'import { useState } from "react";\nimport {\n  useListAgents,\n  useEvolveAgent,\n  useDeleteAgent,\n  useAgentChat,\n  useCreateAgent,\n  getListAgentsQueryKey,\n} from "@workspace/api-client-react";\nimport { useQueryClient } from "@tanstack/react-query";\nimport { Button } from "@/components/ui/button";\nimport { Input } from "@/components/ui/input";\nimport { ScrollArea } from "@/components/ui/scroll-area";\nimport { Textarea } from "@/components/ui/textarea";\nimport { Brain, Zap, Trash2, Plus, Send, X, TrendingUp } from "lucide-react";\nimport { toast } from "sonner";\n\ntype AgentChatMsg = { role: "user" | "assistant"; content: string };\n\nexport default function Agents() {\n  const { data: agents } = useListAgents();\n  const evolveAgent = useEvolveAgent();\n  const deleteAgent = useDeleteAgent();\n  const agentChat = useAgentChat();\n  const createAgent = useCreateAgent();\n  const queryClient = useQueryClient();\n\n  const [chatTarget, setChatTarget] = useState<number | null>(null);\n  const [chatHistory, setChatHistory] = useState<AgentChatMsg[]>([]);\n  const [chatInput, setChatInput] = useState("");\n  const [isChatting, setIsChatting] = useState(false);\n\n  const [showCreate, setShowCreate] = useState(false);\n  const [newName, setNewName] = useState("");\n  const [newRole, setNewRole] = useState("");\n  const [newPrompt, setNewPrompt] = useState("");\n\n  const handleEvolve = (id: number) => {\n    evolveAgent.mutate({ id }, {\n      onSuccess: (agent) => {\n        queryClient.invalidateQueries({ queryKey: getListAgentsQueryKey() });\n        toast.success(`${agent.name} evoluiu para Gen ${agent.gen}!`);\n      },\n      onError: () => toast.error("Falha ao evoluir agente"),\n    });\n  };\n\n  const handleDelete = (id: number, name: string) => {\n    deleteAgent.mutate({ id }, {\n      onSuccess: () => {\n        if (chatTarget === id) { setChatTarget(null); setChatHistory([]); }\n        queryClient.invalidateQueries({ queryKey: getListAgentsQueryKey() });\n        toast.success(`${name} desativado`);\n      },\n    });\n  };\n\n  const openChat = (id: number) => {\n    setChatTarget(id);\n    setChatHistory([]);\n    setChatInput("");\n  };\n\n  const handleSendChat = () => {\n    if (!chatInput.trim() || !chatTarget || isChatting) return;\n    const msg = chatInput.trim();\n    setChatInput("");\n    const updatedHistory: AgentChatMsg[] = [...chatHistory, { role: "user", content: msg }];\n    setChatHistory(updatedHistory);\n    setIsChatting(true);\n\n    agentChat.mutate(\n      { id: chatTarget, data: { message: msg, history: chatHistory } },\n      {\n        onSuccess: (res) => {\n          setChatHistory(prev => [...prev, { role: "assistant", content: res.response }]);\n          queryClient.invalidateQueries({ queryKey: getListAgentsQueryKey() });\n        },\n        onError: () => {\n          setChatHistory(prev => [...prev, { role: "assistant", content: "❌ Erro de comunicação." }]);\n        },\n        onSettled: () => setIsChatting(false),\n      }\n    );\n  };\n\n  const handleCreate = () => {\n    if (!newName.trim() || !newRole.trim()) return;\n    createAgent.mutate(\n      { data: { name: newName.toUpperCase(), role: newRole, system_prompt: newPrompt } },\n      {\n        onSuccess: () => {\n          queryClient.invalidateQueries({ queryKey: getListAgentsQueryKey() });\n          setNewName(""); setNewRole(""); setNewPrompt(""); setShowCreate(false);\n          toast.success("Agente instanciado na rede");\n        },\n      }\n    );\n  };\n\n  const activeAgent = agents?.find(a => a.id === chatTarget);\n\n  return (\n    <div className="p-6 md:p-8 h-full flex flex-col max-w-7xl mx-auto w-full relative z-10">\n      <div className="flex items-center justify-between mb-6">\n        <div>\n          <h1 className="text-3xl font-bold text-primary tracking-tighter drop-shadow-[0_0_15px_var(--color-primary)] flex items-center gap-3">\n            <Brain className="w-8 h-8" /> Rede de Agentes\n          </h1>\n          <p className="text-muted-foreground mt-1 font-mono text-sm">\n            {agents?.length ?? 0} entidades cognitivas ativas\n          </p>\n        </div>\n        <Button\n          onClick={() => setShowCreate(v => !v)}\n          className="bg-primary/20 hover:bg-primary/30 text-primary border border-primary/30"\n          variant="outline"\n          data-testid="button-create-agent"\n        >\n          <Plus className="w-4 h-4 mr-2" /> Novo Agente\n        </Button>\n      </div>\n\n      {showCreate && (\n        <div className="bg-card/50 border border-primary/30 rounded-xl p-5 mb-6 shadow-[0_0_20px_rgba(147,51,234,0.1)]">\n          <h2 className="font-bold text-primary mb-4 font-mono">Instanciar Novo Agente</h2>\n          <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-3">\n            <Input placeholder="Nome (ex: NOVA)" value={newName} onChange={e => setNewName(e.target.value)}\n              className="bg-background border-primary/30 font-mono uppercase" data-testid="input-agent-name" />\n            <Input placeholder="Papel (ex: Estrategista)" value={newRole} onChange={e => setNewRole(e.target.value)}\n              className="bg-background border-primary/30 font-mono" data-testid="input-agent-role" />\n          </div>\n          <Textarea placeholder="Prompt de sistema (opcional)..." value={newPrompt} onChange={e => setNewPrompt(e.target.value)}\n            className="bg-background border-primary/30 font-mono mb-3 h-20" data-testid="input-agent-prompt" />\n          <div className="flex gap-2">\n            <Button onClick={handleCreate} disabled={createAgent.isPending} className="bg-primary hover:bg-primary/80" data-testid="button-confirm-create-agent">\n              <Plus className="w-4 h-4 mr-2" /> Instanciar\n            </Button>\n            <Button variant="ghost" onClick={() => setShowCreate(false)}>Cancelar</Button>\n          </div>\n        </div>\n      )}\n\n      <div className="flex gap-6 flex-1 min-h-0">\n        {/* Agent Grid */}\n        <div className="flex-1 min-h-0 overflow-auto">\n          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 pb-4">\n            {agents?.map(agent => (\n              <div\n                key={agent.id}\n                className={`border rounded-xl p-5 bg-card/60 backdrop-blur transition-all shadow-lg group relative overflow-hidden cursor-pointer\n                  ${chatTarget === agent.id ? \'border-primary/60 shadow-[0_0_20px_rgba(147,51,234,0.2)]\' : \'border-border/50 hover:border-primary/40\'}`}\n                style={{ borderTopColor: agent.color }}\n                onClick={() => openChat(agent.id)}\n                data-testid={`card-agent-${agent.id}`}\n              >\n                <div className="absolute top-0 left-0 right-0 h-0.5" style={{ background: agent.color }} />\n\n                <div className="flex items-start justify-between mb-3">\n                  <div className="flex items-center gap-3">\n                    <span className="text-3xl">{agent.avatar}</span>\n                    <div>\n                      <h3 className="font-bold text-sm tracking-widest uppercase" style={{ color: agent.color }}>\n                        {agent.name}\n                      </h3>\n                      <p className="text-xs text-muted-foreground">{agent.role}</p>\n                    </div>\n                  </div>\n                  <Button\n                    variant="ghost" size="icon"\n                    className="h-7 w-7 text-muted-foreground hover:text-destructive opacity-0 group-hover:opacity-100 transition-opacity"\n                    onClick={e => { e.stopPropagation(); handleDelete(agent.id, agent.name); }}\n                    data-testid={`button-delete-agent-${agent.id}`}\n                  >\n                    <Trash2 className="w-3.5 h-3.5" />\n                  </Button>\n                </div>\n\n                {/* Stats */}\n                <div className="space-y-2 mb-4">\n                  {[\n                    { label: "Fitness", val: agent.fitness },\n                    { label: "Criatividade", val: agent.creativity },\n                    { label: "Curiosidade", val: agent.curiosity },\n                  ].map(({ label, val }) => (\n                    <div key={label}>\n                      <div className="flex justify-between text-xs mb-1">\n                        <span className="text-muted-foreground font-mono">{label}</span>\n                        <span className="font-mono" style={{ color: agent.color }}>{(val ?? 0).toFixed(0)}</span>\n                      </div>\n                      <div className="h-1.5 bg-background rounded-full overflow-hidden border border-border/30">\n                        <div className="h-full rounded-full transition-all duration-500"\n                          style={{ width: `${val ?? 0}%`, background: agent.color, boxShadow: `0 0 6px ${agent.color}` }} />\n                      </div>\n                    </div>\n                  ))}\n                </div>\n\n                <div className="flex items-center justify-between">\n                  <div className="flex gap-2 text-xs font-mono text-muted-foreground">\n                    <span className="px-2 py-0.5 rounded bg-background/60 border border-border/30">Gen {agent.gen}</span>\n                    <span className="px-2 py-0.5 rounded bg-background/60 border border-border/30">{agent.messages_count} msgs</span>\n                  </div>\n                  <Button\n                    size="sm"\n                    variant="outline"\n                    className="h-7 text-xs border-primary/30 text-primary hover:bg-primary/10"\n                    onClick={e => { e.stopPropagation(); handleEvolve(agent.id); }}\n                    disabled={evolveAgent.isPending}\n                    data-testid={`button-evolve-agent-${agent.id}`}\n                  >\n                    <TrendingUp className="w-3 h-3 mr-1" /> Evoluir\n                  </Button>\n                </div>\n              </div>\n            ))}\n          </div>\n        </div>\n\n        {/* Chat Panel */}\n        {chatTarget && activeAgent && (\n          <div className="w-80 xl:w-96 flex flex-col border border-primary/30 rounded-xl bg-card/50 backdrop-blur shadow-[0_0_25px_rgba(147,51,234,0.1)] shrink-0">\n            <div className="p-4 border-b border-border/50 flex items-center justify-between">\n              <div className="flex items-center gap-2">\n                <span className="text-xl">{activeAgent.avatar}</span>\n                <div>\n                  <p className="font-bold text-sm" style={{ color: activeAgent.color }}>{activeAgent.name}</p>\n                  <p className="text-xs text-muted-foreground">Conversa direta</p>\n                </div>\n              </div>\n              <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => { setChatTarget(null); setChatHistory([]); }}>\n                <X className="w-4 h-4" />\n              </Button>\n            </div>\n\n            <ScrollArea className="flex-1 p-4">\n              <div className="space-y-3">\n                {chatHistory.length === 0 && (\n                  <p className="text-xs text-muted-foreground text-center font-mono py-8">\n                    Inicie a comunicação com {activeAgent.name}\n                  </p>\n                )}\n                {chatHistory.map((m, i) => (\n                  <div key={i} className={`flex ${m.role === "user" ? "justify-end" : "justify-start"}`}>\n                    <div className={`max-w-[85%] rounded-xl px-3 py-2 text-sm font-mono ${\n                      m.role === "user"\n                        ? "bg-primary/20 text-primary-foreground border border-primary/30"\n                        : "bg-background border border-border/50 text-foreground"\n                    }`}>\n                      {m.content}\n                    </div>\n                  </div>\n                ))}\n                {isChatting && (\n                  <div className="flex justify-start">\n                    <div className="bg-background border border-border/50 rounded-xl px-3 py-2 text-sm font-mono">\n                      <span className="animate-pulse">▋</span>\n                    </div>\n                  </div>\n                )}\n              </div>\n            </ScrollArea>\n\n            <div className="p-3 border-t border-border/50 flex gap-2">\n              <Input\n                value={chatInput}\n                onChange={e => setChatInput(e.target.value)}\n                onKeyDown={e => e.key === "Enter" && !e.shiftKey && (e.preventDefault(), handleSendChat())}\n                placeholder="Mensagem..."\n                className="bg-background border-primary/20 font-mono text-sm h-9"\n                disabled={isChatting}\n                data-testid="input-agent-chat"\n              />\n              <Button\n                size="icon"\n                className="h-9 w-9 bg-primary hover:bg-primary/80 shrink-0"\n                onClick={handleSendChat}\n                disabled={!chatInput.trim() || isChatting}\n                data-testid="button-send-agent-chat"\n              >\n                <Send className="w-3.5 h-3.5" />\n              </Button>\n            </div>\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n'

