SOURCE_CODE['artifacts/kokusen/src/pages/consciousness.tsx'] = 'import { useGetConsciousness, useGetVitals, getGetVitalsQueryKey, getGetConsciousnessQueryKey } from "@workspace/api-client-react";\nimport { Activity, Server, Zap, Cpu, Network } from "lucide-react";\nimport { ScrollArea } from "@/components/ui/scroll-area";\n\nexport default function Consciousness() {\n  const { data: vitals } = useGetVitals({ query: { refetchInterval: 10000, queryKey: getGetVitalsQueryKey() } });\n  const { data: stream } = useGetConsciousness({ limit: 50 }, { query: { refetchInterval: 5000, queryKey: getGetConsciousnessQueryKey({ limit: 50 }) } });\n\n  return (\n    <div className="p-6 md:p-10 h-full flex flex-col max-w-7xl mx-auto w-full relative z-10">\n      <div className="flex items-center justify-between mb-8">\n        <div>\n          <h1 className="text-3xl font-bold text-accent tracking-tighter drop-shadow-[0_0_15px_var(--color-accent)] flex items-center gap-3">\n            <Activity className="w-8 h-8" /> Fluxo de Consciência\n          </h1>\n          <p className="text-muted-foreground mt-2 font-mono text-sm">Monitoramento em tempo real das atividades cognitivas e sinais vitais.</p>\n        </div>\n      </div>\n\n      {/* Vitals Dashboard */}\n      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">\n        <div className="bg-card/40 border border-border/50 backdrop-blur rounded-xl p-4 flex flex-col">\n          <div className="flex items-center gap-2 text-muted-foreground mb-2 text-sm font-mono"><Server className="w-4 h-4 text-primary" /> Agentes Ativos</div>\n          <div className="text-3xl font-bold text-foreground">{vitals?.agents_online || 0} <span className="text-lg text-muted-foreground">/ {vitals?.total_agents || 0}</span></div>\n        </div>\n        <div className="bg-card/40 border border-border/50 backdrop-blur rounded-xl p-4 flex flex-col">\n          <div className="flex items-center gap-2 text-muted-foreground mb-2 text-sm font-mono"><Zap className="w-4 h-4 text-accent" /> Fitness Médio</div>\n          <div className="text-3xl font-bold text-foreground">{vitals?.avg_fitness?.toFixed(1) || 0}</div>\n        </div>\n        <div className="bg-card/40 border border-border/50 backdrop-blur rounded-xl p-4 flex flex-col">\n          <div className="flex items-center gap-2 text-muted-foreground mb-2 text-sm font-mono"><Network className="w-4 h-4 text-secondary" /> Geração da Rede</div>\n          <div className="text-3xl font-bold text-foreground">{vitals?.network_gen || 0}</div>\n        </div>\n        <div className="bg-card/40 border border-border/50 backdrop-blur rounded-xl p-4 flex flex-col">\n          <div className="flex items-center gap-2 text-muted-foreground mb-2 text-sm font-mono"><Cpu className="w-4 h-4 text-primary" /> Provedor Core</div>\n          <div className="text-xl font-bold text-foreground uppercase tracking-widest mt-1">{vitals?.provider || \'N/A\'}</div>\n        </div>\n      </div>\n\n      {/* Terminal Stream */}\n      <div className="flex-1 bg-black/50 border border-primary/20 rounded-xl overflow-hidden shadow-[0_0_30px_rgba(180,0,255,0.05)] relative flex flex-col">\n        <div className="h-8 bg-card/80 border-b border-primary/20 flex items-center px-4 gap-2">\n          <div className="w-3 h-3 rounded-full bg-destructive/80"></div>\n          <div className="w-3 h-3 rounded-full bg-accent/80"></div>\n          <div className="w-3 h-3 rounded-full bg-primary/80"></div>\n          <span className="text-xs font-mono text-muted-foreground ml-2">sys_stream_log.sh</span>\n        </div>\n        <ScrollArea className="flex-1 p-4 font-mono text-sm">\n          <div className="space-y-1">\n            {stream?.map((entry, i) => (\n              <div key={i} className="flex gap-4 hover:bg-white/5 px-2 py-1 rounded">\n                <span className="text-muted-foreground shrink-0">{entry.time}</span>\n                <span className="text-primary font-bold shrink-0 w-24">[{entry.agent}]</span>\n                <span className={`${entry.type === \'error\' ? \'text-destructive\' : entry.type === \'thought\' ? \'text-accent/80\' : \'text-foreground/80\'} break-words`}>\n                  {entry.content}\n                </span>\n              </div>\n            ))}\n            {!stream?.length && (\n              <div className="text-muted-foreground">Aguardando sinais vitais do sistema neural...</div>\n            )}\n          </div>\n        </ScrollArea>\n      </div>\n    </div>\n  );\n}\n'

