SOURCE_CODE['artifacts/kokusen/src/pages/memory.tsx'] = 'import { useListMemories, useAddMemory, useDeleteMemory, getListMemoriesQueryKey } from "@workspace/api-client-react";\nimport { useQueryClient } from "@tanstack/react-query";\nimport { Button } from "@/components/ui/button";\nimport { Input } from "@/components/ui/input";\nimport { useState } from "react";\nimport { Database, Plus, Trash2, BrainCircuit } from "lucide-react";\nimport { toast } from "sonner";\n\nexport default function Memory() {\n  const { data: memories } = useListMemories();\n  const addMemory = useAddMemory();\n  const deleteMemory = useDeleteMemory();\n  const queryClient = useQueryClient();\n  \n  const [content, setContent] = useState("");\n  const [importance, setImportance] = useState(5);\n\n  const handleCreate = () => {\n    if (!content.trim()) return;\n    addMemory.mutate({ data: { content, importance } }, {\n      onSuccess: () => {\n        setContent("");\n        queryClient.invalidateQueries({ queryKey: getListMemoriesQueryKey() });\n        toast.success("Memória indexada");\n      }\n    });\n  };\n\n  const handleDelete = (id: number) => {\n    deleteMemory.mutate({ id }, {\n      onSuccess: () => {\n        queryClient.invalidateQueries({ queryKey: getListMemoriesQueryKey() });\n        toast.success("Memória expurgada");\n      }\n    });\n  };\n\n  return (\n    <div className="p-6 md:p-10 h-full flex flex-col max-w-6xl mx-auto w-full relative z-10">\n      <div className="flex items-center justify-between mb-8">\n        <div>\n          <h1 className="text-3xl font-bold text-secondary tracking-tighter drop-shadow-[0_0_15px_var(--color-secondary)] flex items-center gap-3">\n            <Database className="w-8 h-8" /> Banco de Memória\n          </h1>\n          <p className="text-muted-foreground mt-2 font-mono text-sm">Armazenamento persistente de contexto e fragmentos de conhecimento.</p>\n        </div>\n      </div>\n\n      <div className="bg-card/40 border border-secondary/30 backdrop-blur-md rounded-xl p-6 shadow-[0_0_20px_rgba(0,100,255,0.1)] mb-8">\n        <h2 className="text-lg font-bold mb-4 flex items-center gap-2 text-secondary"><BrainCircuit className="w-5 h-5"/> Injetar Nova Memória</h2>\n        <div className="flex gap-4">\n          <Input \n            placeholder="Conteúdo da memória..." \n            value={content} \n            onChange={(e) => setContent(e.target.value)} \n            className="bg-background border-secondary/30 font-mono focus-visible:ring-secondary flex-1"\n          />\n          <Input \n            type="number"\n            min="1" max="10"\n            value={importance}\n            onChange={(e) => setImportance(Number(e.target.value))}\n            className="w-24 bg-background border-secondary/30 font-mono focus-visible:ring-secondary"\n          />\n          <Button onClick={handleCreate} className="bg-secondary text-secondary-foreground hover:bg-secondary/80 shadow-[0_0_15px_var(--color-secondary)]">\n            <Plus className="w-4 h-4 mr-2" /> Indexar\n          </Button>\n        </div>\n      </div>\n\n      <div className="grid grid-cols-1 gap-3 flex-1 overflow-auto pb-10">\n        {memories?.map(memory => (\n          <div key={memory.id} className="border border-border/50 rounded-lg p-4 bg-card/60 backdrop-blur hover:border-secondary/50 transition-colors flex items-center justify-between group">\n            <div className="flex items-center gap-4 flex-1">\n              <div className={`w-8 h-8 rounded bg-background border flex items-center justify-center font-mono font-bold text-sm ${memory.importance > 7 ? \'border-accent text-accent shadow-[0_0_10px_var(--color-accent)]\' : \'border-secondary/50 text-secondary\'}`}>\n                {memory.importance}\n              </div>\n              <p className="text-sm font-mono text-foreground/90">{memory.content}</p>\n            </div>\n            <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-destructive opacity-0 group-hover:opacity-100 transition-opacity" onClick={() => handleDelete(memory.id)}>\n              <Trash2 className="w-4 h-4" />\n            </Button>\n          </div>\n        ))}\n      </div>\n    </div>\n  );\n}\n'

