SOURCE_CODE['artifacts/kokusen/src/pages/projects.tsx'] = 'import { useListProjects, useCreateProject, useDeleteProject, getListProjectsQueryKey } from "@workspace/api-client-react";\nimport { useQueryClient } from "@tanstack/react-query";\nimport { Button } from "@/components/ui/button";\nimport { Input } from "@/components/ui/input";\nimport { useState } from "react";\nimport { FolderGit2, Plus, Trash2 } from "lucide-react";\nimport { toast } from "sonner";\n\nexport default function Projects() {\n  const { data: projects } = useListProjects();\n  const createProject = useCreateProject();\n  const deleteProject = useDeleteProject();\n  const queryClient = useQueryClient();\n  \n  const [name, setName] = useState("");\n\n  const handleCreate = () => {\n    if (!name.trim()) return;\n    createProject.mutate({ data: { name, color: "#9333ea", icon: "📁" } }, {\n      onSuccess: () => {\n        setName("");\n        queryClient.invalidateQueries({ queryKey: getListProjectsQueryKey() });\n        toast.success("Projeto criado");\n      }\n    });\n  };\n\n  const handleDelete = (id: number) => {\n    deleteProject.mutate({ id }, {\n      onSuccess: () => {\n        queryClient.invalidateQueries({ queryKey: getListProjectsQueryKey() });\n        toast.success("Projeto removido");\n      }\n    });\n  };\n\n  return (\n    <div className="p-6 md:p-10 h-full flex flex-col max-w-6xl mx-auto w-full relative z-10">\n      <div className="flex items-center justify-between mb-8">\n        <div>\n          <h1 className="text-3xl font-bold text-primary tracking-tighter drop-shadow-[0_0_15px_var(--color-primary)] flex items-center gap-3">\n            <FolderGit2 className="w-8 h-8" /> Workspace de Projetos\n          </h1>\n          <p className="text-muted-foreground mt-2 font-mono text-sm">Organize suas sessões neurais em contextos segregados.</p>\n        </div>\n      </div>\n\n      <div className="bg-card/40 border border-border/50 backdrop-blur-md rounded-xl p-6 shadow-2xl mb-8 flex gap-4">\n        <Input \n          placeholder="Nome do novo projeto..." \n          value={name} \n          onChange={(e) => setName(e.target.value)} \n          className="bg-background border-primary/30 font-mono focus-visible:ring-primary"\n        />\n        <Button onClick={handleCreate} className="bg-primary hover:bg-primary/80 shadow-[0_0_15px_var(--color-primary)]">\n          <Plus className="w-4 h-4 mr-2" /> Criar Workspace\n        </Button>\n      </div>\n\n      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 flex-1 overflow-auto pb-10">\n        {projects?.map(project => (\n          <div key={project.id} className="border border-border/50 rounded-xl p-6 bg-card/60 backdrop-blur hover:border-primary/50 transition-colors shadow-lg group relative overflow-hidden">\n            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-primary to-accent opacity-50"></div>\n            <div className="flex justify-between items-start mb-4">\n              <div className="text-4xl">{project.icon}</div>\n              <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-destructive opacity-0 group-hover:opacity-100 transition-opacity" onClick={() => handleDelete(project.id)}>\n                <Trash2 className="w-4 h-4" />\n              </Button>\n            </div>\n            <h3 className="text-xl font-bold tracking-tight mb-2 text-foreground">{project.name}</h3>\n            <div className="flex items-center gap-2 mt-4 text-xs font-mono text-muted-foreground">\n              <div className="px-2 py-1 rounded bg-background/50 border border-border/50">\n                {project.chat_count || 0} sessões\n              </div>\n            </div>\n          </div>\n        ))}\n      </div>\n    </div>\n  );\n}\n'

