SOURCE_CODE['artifacts/kokusen/src/pages/settings.tsx'] = 'import { useGetSettings, useSaveSettings, getGetSettingsQueryKey } from "@workspace/api-client-react";\nimport { useQueryClient } from "@tanstack/react-query";\nimport { Button } from "@/components/ui/button";\nimport { Input } from "@/components/ui/input";\nimport { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";\nimport { Switch } from "@/components/ui/switch";\nimport { useState, useEffect } from "react";\nimport { Settings as SettingsIcon, Save, Eye, EyeOff, Download, Upload } from "lucide-react";\nimport { toast } from "sonner";\n\nexport default function Settings() {\n  const { data: initialSettings } = useGetSettings();\n  const saveSettings = useSaveSettings();\n  const queryClient = useQueryClient();\n\n  const [provider, setProvider] = useState("groq");\n  const [apiKey, setApiKey] = useState("");\n  const [modelGroq, setModelGroq] = useState("llama-3.3-70b-versatile");\n  const [modelOpenai, setModelOpenai] = useState("gpt-4o-mini");\n  const [modelAnthropic, setModelAnthropic] = useState("claude-3-5-haiku-20241022");\n  const [profileName, setProfileName] = useState("");\n  const [autoMemory, setAutoMemory] = useState(false);\n  const [consciousnessActive, setConsciousnessActive] = useState(true);\n  const [showInsights, setShowInsights] = useState(true);\n  const [showKey, setShowKey] = useState(false);\n\n  useEffect(() => {\n    if (!initialSettings) return;\n    setProvider(initialSettings.api_provider ?? "groq");\n    setModelGroq(initialSettings.model_groq ?? "llama-3.3-70b-versatile");\n    setModelOpenai(initialSettings.model_openai ?? "gpt-4o-mini");\n    setModelAnthropic(initialSettings.model_anthropic ?? "claude-3-5-haiku-20241022");\n    setProfileName(initialSettings.profile_name ?? "");\n    setAutoMemory(initialSettings.auto_memory === "true");\n    setConsciousnessActive(initialSettings.consciousness_active === "true");\n    setShowInsights(initialSettings.show_insights === "true");\n  }, [initialSettings]);\n\n  const handleSave = () => {\n    const payload: Record<string, string> = {\n      api_provider: provider,\n      model_groq: modelGroq,\n      model_openai: modelOpenai,\n      model_anthropic: modelAnthropic,\n      profile_name: profileName,\n      auto_memory: autoMemory ? "true" : "false",\n      consciousness_active: consciousnessActive ? "true" : "false",\n      show_insights: showInsights ? "true" : "false",\n    };\n    // Save the actual API key under the correct provider key\n    if (apiKey.trim()) {\n      payload[`api_key_${provider}`] = apiKey.trim();\n    }\n\n    saveSettings.mutate({ data: payload }, {\n      onSuccess: () => {\n        queryClient.invalidateQueries({ queryKey: getGetSettingsQueryKey() });\n        setApiKey("");\n        toast.success("Configurações salvas com sucesso");\n      },\n      onError: () => toast.error("Erro ao salvar configurações"),\n    });\n  };\n\n  const handleExport = async () => {\n    try {\n      const res = await fetch("/api/backup/export");\n      const data = await res.json();\n      const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });\n      const url = URL.createObjectURL(blob);\n      const a = document.createElement("a");\n      a.href = url;\n      a.download = `kokusen_backup_${new Date().toISOString().slice(0, 10)}.json`;\n      a.click();\n      URL.revokeObjectURL(url);\n      toast.success("Backup exportado");\n    } catch {\n      toast.error("Erro ao exportar backup");\n    }\n  };\n\n  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {\n    const file = e.target.files?.[0];\n    if (!file) return;\n    const reader = new FileReader();\n    reader.onload = async (ev) => {\n      try {\n        const data = JSON.parse(ev.target?.result as string);\n        await fetch("/api/backup/import", {\n          method: "POST",\n          headers: { "Content-Type": "application/json" },\n          body: JSON.stringify(data),\n        });\n        toast.success("Backup importado com sucesso");\n        queryClient.invalidateQueries();\n      } catch {\n        toast.error("Erro ao importar backup");\n      }\n    };\n    reader.readAsText(file);\n    e.target.value = "";\n  };\n\n  return (\n    <div className="p-6 md:p-10 h-full overflow-auto relative z-10">\n      <div className="max-w-3xl mx-auto">\n        <div className="flex items-center justify-between mb-8">\n          <div>\n            <h1 className="text-3xl font-bold text-foreground tracking-tighter flex items-center gap-3">\n              <SettingsIcon className="w-8 h-8 text-primary" /> Configurações do Sistema\n            </h1>\n            <p className="text-muted-foreground mt-2 font-mono text-sm">Ajustes do núcleo de processamento e credenciais.</p>\n          </div>\n          <Button\n            onClick={handleSave}\n            disabled={saveSettings.isPending}\n            className="bg-primary hover:bg-primary/80 shadow-[0_0_15px_var(--color-primary)]"\n            data-testid="button-save-settings"\n          >\n            <Save className="w-4 h-4 mr-2" /> {saveSettings.isPending ? "Salvando..." : "Salvar"}\n          </Button>\n        </div>\n\n        <div className="space-y-6">\n          {/* API Config */}\n          <div className="bg-card/40 border border-border/50 backdrop-blur-md rounded-xl p-6 shadow-lg">\n            <h2 className="text-lg font-bold mb-4 font-mono text-primary border-b border-border/50 pb-2">Provedor e Modelos</h2>\n\n            <div className="space-y-4">\n              <div className="grid gap-2">\n                <label className="text-sm font-medium text-muted-foreground">Provedor Principal</label>\n                <Select value={provider} onValueChange={setProvider}>\n                  <SelectTrigger className="bg-background border-border/50" data-testid="select-provider">\n                    <SelectValue />\n                  </SelectTrigger>\n                  <SelectContent>\n                    <SelectItem value="groq">Groq (Ultra-rápido)</SelectItem>\n                    <SelectItem value="openai">OpenAI (GPT-4o)</SelectItem>\n                    <SelectItem value="anthropic">Anthropic (Claude)</SelectItem>\n                  </SelectContent>\n                </Select>\n              </div>\n\n              <div className="grid gap-2">\n                <label className="text-sm font-medium text-muted-foreground">\n                  Chave API {provider.toUpperCase()}\n                  {initialSettings?.has_api_key === "true" && (\n                    <span className="ml-2 text-xs text-green-400 font-mono">✓ configurada ({initialSettings.api_key_masked})</span>\n                  )}\n                </label>\n                <div className="relative">\n                  <Input\n                    type={showKey ? "text" : "password"}\n                    value={apiKey}\n                    placeholder="Cole sua chave aqui para atualizar..."\n                    onChange={e => setApiKey(e.target.value)}\n                    className="bg-background border-border/50 font-mono pr-10"\n                    data-testid="input-api-key"\n                  />\n                  <Button\n                    variant="ghost" size="icon"\n                    className="absolute right-1 top-1 h-8 w-8 text-muted-foreground"\n                    onClick={() => setShowKey(v => !v)}\n                    type="button"\n                  >\n                    {showKey ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}\n                  </Button>\n                </div>\n              </div>\n\n              <div className="grid grid-cols-1 gap-3">\n                <div className="grid gap-2">\n                  <label className="text-xs font-medium text-muted-foreground font-mono">Modelo Groq</label>\n                  <Select value={modelGroq} onValueChange={setModelGroq}>\n                    <SelectTrigger className="bg-background border-border/50 text-sm">\n                      <SelectValue />\n                    </SelectTrigger>\n                    <SelectContent>\n                      <SelectItem value="llama-3.3-70b-versatile">llama-3.3-70b-versatile</SelectItem>\n                      <SelectItem value="llama-3.1-8b-instant">llama-3.1-8b-instant</SelectItem>\n                      <SelectItem value="mixtral-8x7b-32768">mixtral-8x7b-32768</SelectItem>\n                      <SelectItem value="gemma2-9b-it">gemma2-9b-it</SelectItem>\n                    </SelectContent>\n                  </Select>\n                </div>\n                <div className="grid gap-2">\n                  <label className="text-xs font-medium text-muted-foreground font-mono">Modelo OpenAI</label>\n                  <Select value={modelOpenai} onValueChange={setModelOpenai}>\n                    <SelectTrigger className="bg-background border-border/50 text-sm">\n                      <SelectValue />\n                    </SelectTrigger>\n                    <SelectContent>\n                      <SelectItem value="gpt-4o-mini">gpt-4o-mini</SelectItem>\n                      <SelectItem value="gpt-4o">gpt-4o</SelectItem>\n                      <SelectItem value="gpt-4-turbo">gpt-4-turbo</SelectItem>\n                      <SelectItem value="gpt-3.5-turbo">gpt-3.5-turbo</SelectItem>\n                    </SelectContent>\n                  </Select>\n                </div>\n                <div className="grid gap-2">\n                  <label className="text-xs font-medium text-muted-foreground font-mono">Modelo Anthropic</label>\n                  <Select value={modelAnthropic} onValueChange={setModelAnthropic}>\n                    <SelectTrigger className="bg-background border-border/50 text-sm">\n                      <SelectValue />\n                    </SelectTrigger>\n                    <SelectContent>\n                      <SelectItem value="claude-3-5-haiku-20241022">claude-3-5-haiku-20241022</SelectItem>\n                      <SelectItem value="claude-3-5-sonnet-20241022">claude-3-5-sonnet-20241022</SelectItem>\n                      <SelectItem value="claude-3-opus-20240229">claude-3-opus-20240229</SelectItem>\n                    </SelectContent>\n                  </Select>\n                </div>\n              </div>\n            </div>\n          </div>\n\n          {/* Behavior */}\n          <div className="bg-card/40 border border-border/50 backdrop-blur-md rounded-xl p-6 shadow-lg">\n            <h2 className="text-lg font-bold mb-4 font-mono text-accent border-b border-border/50 pb-2">Comportamento Neural</h2>\n            <div className="space-y-5">\n              {[\n                { label: "Consciência Ativa", desc: "Agentes pensam e interagem em background", state: consciousnessActive, set: setConsciousnessActive, id: "switch-consciousness" },\n                { label: "Auto-Memória", desc: "Extração automática de contexto das conversas", state: autoMemory, set: setAutoMemory, id: "switch-auto-memory" },\n                { label: "Mostrar Insights", desc: "Exibir fragmentos de sabedoria no chat", state: showInsights, set: setShowInsights, id: "switch-insights" },\n              ].map(({ label, desc, state, set, id }) => (\n                <div key={label} className="flex items-center justify-between">\n                  <div>\n                    <p className="font-medium text-foreground">{label}</p>\n                    <p className="text-sm text-muted-foreground font-mono">{desc}</p>\n                  </div>\n                  <Switch\n                    checked={state}\n                    onCheckedChange={set}\n                    className="data-[state=checked]:bg-accent"\n                    data-testid={id}\n                  />\n                </div>\n              ))}\n            </div>\n          </div>\n\n          {/* Profile */}\n          <div className="bg-card/40 border border-border/50 backdrop-blur-md rounded-xl p-6 shadow-lg">\n            <h2 className="text-lg font-bold mb-4 font-mono text-foreground border-b border-border/50 pb-2">Perfil</h2>\n            <Input\n              placeholder="Seu nome..."\n              value={profileName}\n              onChange={e => setProfileName(e.target.value)}\n              className="bg-background border-border/50 font-mono"\n              data-testid="input-profile-name"\n            />\n          </div>\n\n          {/* Backup */}\n          <div className="bg-card/40 border border-border/50 backdrop-blur-md rounded-xl p-6 shadow-lg">\n            <h2 className="text-lg font-bold mb-4 font-mono text-foreground border-b border-border/50 pb-2">Backup & Restauração</h2>\n            <div className="flex gap-3">\n              <Button variant="outline" onClick={handleExport} className="border-border/50" data-testid="button-export-backup">\n                <Download className="w-4 h-4 mr-2" /> Exportar Backup\n              </Button>\n              <label>\n                <Button variant="outline" className="border-border/50 cursor-pointer" asChild>\n                  <span data-testid="button-import-backup">\n                    <Upload className="w-4 h-4 mr-2" /> Importar Backup\n                  </span>\n                </Button>\n                <input type="file" accept=".json" className="hidden" onChange={handleImport} />\n              </label>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n'

