SOURCE_CODE['artifacts/kokusen/src/App.tsx'] = 'import { Switch, Route, Router as WouterRouter, Link, useLocation } from "wouter";\nimport { QueryClient, QueryClientProvider } from "@tanstack/react-query";\nimport { Toaster } from "@/components/ui/toaster";\nimport { TooltipProvider } from "@/components/ui/tooltip";\nimport { Brain, Activity, Settings as SettingsIcon, MessageSquare, Archive, Database, BarChart2 } from "lucide-react";\nimport NotFound from "@/pages/not-found";\nimport Chat from "@/pages/chat";\nimport Agents from "@/pages/agents";\nimport Projects from "@/pages/projects";\nimport Consciousness from "@/pages/consciousness";\nimport Memory from "@/pages/memory";\nimport Settings from "@/pages/settings";\nimport Stats from "@/pages/stats";\n\nconst queryClient = new QueryClient();\n\nfunction Layout({ children }: { children: React.ReactNode }) {\n  const [location] = useLocation();\n\n  const navItems = [\n    { href: "/", icon: MessageSquare, label: "Chat" },\n    { href: "/agents", icon: Brain, label: "Agentes" },\n    { href: "/projects", icon: Archive, label: "Projetos" },\n    { href: "/consciousness", icon: Activity, label: "Consciência" },\n    { href: "/memory", icon: Database, label: "Memória" },\n    { href: "/stats", icon: BarChart2, label: "Estatísticas" },\n    { href: "/settings", icon: SettingsIcon, label: "Configurações" },\n  ];\n\n  return (\n    <div className="flex h-screen w-full bg-background text-foreground overflow-hidden font-sans">\n      <aside className="w-16 md:w-64 border-r border-border bg-card flex flex-col items-center md:items-start py-4 relative z-10 shadow-2xl">\n        <div className="px-4 mb-8 hidden md:block w-full">\n          <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-primary to-accent tracking-tighter">\n            KokusenAI\n          </h1>\n          <div className="h-[1px] w-full bg-gradient-to-r from-primary/50 to-transparent mt-2"></div>\n        </div>\n        <nav className="flex-1 w-full space-y-1 px-2">\n          {navItems.map((item) => {\n            const isActive = location === item.href;\n            return (\n              <Link key={item.href} href={item.href} className={`flex items-center gap-3 px-3 py-3 rounded-md transition-all duration-300 relative overflow-hidden group ${isActive ? \'text-primary bg-primary/10\' : \'text-muted-foreground hover:text-foreground hover:bg-muted/50\'}`}>\n                {isActive && (\n                  <div className="absolute left-0 top-0 bottom-0 w-1 bg-primary shadow-[0_0_10px_var(--color-primary)]"></div>\n                )}\n                <item.icon className={`w-5 h-5 ${isActive ? \'drop-shadow-[0_0_5px_var(--color-primary)]\' : \'\'}`} />\n                <span className="hidden md:block font-medium tracking-wide">{item.label}</span>\n              </Link>\n            )\n          })}\n        </nav>\n      </aside>\n\n      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-[radial-gradient(ellipse_at_top_right,_var(--tw-gradient-stops))] from-background via-background to-card/50">\n        {children}\n      </main>\n    </div>\n  );\n}\n\nfunction PlaceholderPage({ title }: { title: string }) {\n  return (\n    <div className="flex-1 flex flex-col h-full p-6 relative z-10">\n      <h1 className="text-3xl font-bold mb-6 text-primary tracking-tighter drop-shadow-[0_0_15px_var(--color-primary)]">{title}</h1>\n      <div className="flex-1 border border-border/50 rounded-xl bg-card/30 backdrop-blur-sm p-6 shadow-2xl">\n        <p className="text-muted-foreground font-mono">Carregando módulo neural {title}...</p>\n      </div>\n    </div>\n  );\n}\n\nfunction Router() {\n  return (\n    <Layout>\n      <Switch>\n        <Route path="/" component={Chat} />\n        <Route path="/agents" component={Agents} />\n        <Route path="/projects" component={Projects} />\n        <Route path="/consciousness" component={Consciousness} />\n        <Route path="/memory" component={Memory} />\n        <Route path="/settings" component={Settings} />\n        <Route path="/stats" component={Stats} />\n        <Route component={NotFound} />\n      </Switch>\n    </Layout>\n  );\n}\n\nfunction App() {\n  return (\n    <QueryClientProvider client={queryClient}>\n      <TooltipProvider>\n        <WouterRouter base={import.meta.env.BASE_URL.replace(/\\/$/, "")}>\n          <Router />\n        </WouterRouter>\n        <Toaster />\n      </TooltipProvider>\n    </QueryClientProvider>\n  );\n}\n\nexport default App;\n'


def print_file(path):
    """Imprime o código fonte de um arquivo específico."""
    if path in SOURCE_CODE:
        print(f"\n{'='*60}")
        print(f"  {path}")
        print('='*60)
        print(SOURCE_CODE[path])
    else:
        print(f"Arquivo '{path}' não encontrado.")
        print("Arquivos disponíveis:")
        for k in SOURCE_CODE:
            print(f"  {k}")

def export_files(output_dir="."):
    """Exporta todos os arquivos fonte para o disco."""
    import os
    exported = 0
    for rel_path, code in SOURCE_CODE.items():
        full = os.path.join(output_dir, rel_path)
        os.makedirs(os.path.dirname(full), exist_ok=True)
        with open(full, 'w', encoding='utf-8') as f:
            f.write(code)
        print(f"  [OK] {rel_path}")
        exported += 1
    print(f"\n{exported} arquivos exportados em: {os.path.abspath(output_dir)}")

if __name__ == "__main__":
    import sys
    if len(sys.argv) > 1:
        if sys.argv[1] == "export":
            dest = sys.argv[2] if len(sys.argv) > 2 else "graham_kokusen_src"
            export_files(dest)
        else:
            print_file(sys.argv[1])
    else:
        print(__doc__)
        print("\nArquivos disponíveis:")
        for k in SOURCE_CODE:
            size = len(SOURCE_CODE[k])
            print(f"  {k:<60}  ({size:,} chars)")
        print("\nUso:")
        print("  python graham_kokusen.py                       # lista arquivos")
        print("  python graham_kokusen.py <caminho>             # mostra arquivo")
        print("  python graham_kokusen.py export [pasta]        # exporta tudo")
